'use client';

import { useRef } from 'react';
import { orbVars, type OrbProps } from '../../lib/orb-state';
import { useOrbLevel } from '../../lib/use-orb-level';
import styles from './pulse-orb.module.css';

export const PulseOrb = ({
  state = 'idle',
  size = 160,
  speed = 1,
  colorFrom,
  colorTo,
  levelRef,
  label = 'Assistant orb',
  className,
}: OrbProps) => {
  const ref = useRef<HTMLDivElement>(null);
  useOrbLevel(ref, state, levelRef);

  return (
    <div
      ref={ref}
      role="img"
      aria-label={label}
      data-state={state}
      className={[styles.orb, className].filter(Boolean).join(' ')}
      style={orbVars({ size, speed, colorFrom, colorTo })}
    >
      <span className={styles.glow} />
      <span className={`${styles.ring} ${styles.ring1}`} />
      <span className={`${styles.ring} ${styles.ring2}`} />
      <span className={`${styles.ring} ${styles.ring3}`} />
      <span className={styles.arc} />
      <span className={styles.core} />
    </div>
  );
};

.orb {
  --orb-size: 160px;
  --orb-speed: 1;
  --orb-color-from: #818cf8;
  --orb-color-to: #22d3ee;
  --orb-level: 0;
  position: relative;
  display: grid;
  place-items: center;
  width: var(--orb-size);
  height: var(--orb-size);
  isolation: isolate;
}

.glow {
  position: absolute;
  width: 70%;
  height: 70%;
  border-radius: 50%;
  background: radial-gradient(circle, var(--orb-color-from), transparent 65%);
  opacity: calc(0.35 + 0.5 * var(--orb-level));
  filter: blur(calc(8px + 22px * var(--orb-level)));
  transition: opacity 0.1s linear;
}

.core {
  position: absolute;
  width: 38%;
  height: 38%;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 30%, var(--orb-color-from), var(--orb-color-to));
  box-shadow: 0 0 calc(16px + 40px * var(--orb-level))
    color-mix(in oklab, var(--orb-color-from), transparent 45%);
  transform: scale(calc(1 + 0.2 * var(--orb-level)));
  transition: transform 0.08s linear;
}

.ring {
  position: absolute;
  width: 42%;
  height: 42%;
  border-radius: 50%;
  border: 2px solid color-mix(in oklab, var(--orb-color-to), transparent 25%);
  opacity: 0;
  animation: orb-ring calc(3s / var(--orb-speed)) ease-out infinite;
}

.ring2 {
  animation-delay: calc(-1s / var(--orb-speed));
}

.ring3 {
  animation-delay: calc(-2s / var(--orb-speed));
}

.arc {
  position: absolute;
  width: 54%;
  height: 54%;
  border-radius: 50%;
  border: 2px solid transparent;
  border-top-color: var(--orb-color-to);
  border-right-color: color-mix(in oklab, var(--orb-color-from), transparent 40%);
  opacity: 0;
  animation: orb-spin calc(1.6s / var(--orb-speed)) linear infinite;
}

.orb[data-state='connecting'] .arc,
.orb[data-state='thinking'] .arc {
  opacity: 1;
}

.orb[data-state='connecting'] .ring,
.orb[data-state='disabled'] .ring {
  opacity: 0;
  animation: none;
}

.orb[data-state='error'] {
  --orb-color-from: #fb7185;
  --orb-color-to: #f43f5e;
}

.orb[data-state='disabled'] {
  filter: grayscale(0.8);
  opacity: 0.5;
}

@keyframes orb-ring {
  0% {
    transform: scale(1);
    opacity: calc(0.45 + 0.5 * var(--orb-level));
  }
  100% {
    transform: scale(2.3);
    opacity: 0;
  }
}

@keyframes orb-spin {
  to {
    transform: rotate(360deg);
  }
}

@media (prefers-reduced-motion: reduce) {
  .ring,
  .arc {
    animation: none;
  }
  .orb[data-state='connecting'] .arc,
  .orb[data-state='thinking'] .arc {
    opacity: 0.6;
  }
}

'use client';

import { useRef } from 'react';
import clsx from 'clsx';
import { orbVars, type OrbProps } from '../../lib/orb-state';
import { useOrbLevel } from '../../lib/use-orb-level';

export const PulseOrbTw = ({
  state = 'idle',
  size = 160,
  speed = 1,
  colorFrom = '#818cf8',
  colorTo = '#22d3ee',
  levelRef,
  label = 'Assistant orb',
  className,
}: OrbProps) => {
  const ref = useRef<HTMLDivElement>(null);
  useOrbLevel(ref, state, levelRef);
  const showArc = state === 'connecting' || state === 'thinking';
  const showRings = state !== 'connecting' && state !== 'disabled';

  return (
    <div
      ref={ref}
      role="img"
      aria-label={label}
      className={clsx('relative grid place-items-center isolate', className)}
      style={{ ...orbVars({ size, speed, colorFrom, colorTo }), width: size, height: size }}
    >
      <span
        className="absolute h-[70%] w-[70%] rounded-full"
        style={{
          background: `radial-gradient(circle, ${colorFrom}, transparent 65%)`,
          opacity: 'calc(0.35 + 0.5 * var(--orb-level))',
          filter: 'blur(calc(8px + 22px * var(--orb-level)))',
        }}
      />
      {showRings &&
        [0, -1, -2].map((delay) => (
          <span
            key={delay}
            className="absolute h-[42%] w-[42%] rounded-full border-2 opacity-0 animate-orb-ring"
            style={{
              borderColor: `color-mix(in oklab, ${colorTo}, transparent 25%)`,
              animationDelay: `calc(${delay}s / var(--orb-speed))`,
            }}
          />
        ))}
      {showArc && (
        <span
          className="absolute h-[54%] w-[54%] rounded-full border-2 border-transparent animate-orb-spin"
          style={{ borderTopColor: colorTo, borderRightColor: `color-mix(in oklab, ${colorFrom}, transparent 40%)` }}
        />
      )}
      <span
        className="absolute h-[38%] w-[38%] rounded-full transition-transform duration-75"
        style={{
          background: `radial-gradient(circle at 35% 30%, ${colorFrom}, ${colorTo})`,
          boxShadow: `0 0 calc(16px + 40px * var(--orb-level)) color-mix(in oklab, ${colorFrom}, transparent 45%)`,
          transform: 'scale(calc(1 + 0.2 * var(--orb-level)))',
        }}
      />
    </div>
  );
};
